// // This module implements a 16-bit DRAM cell with write and read functionalities. It has an input data line (16 bits), a write enable signal (we), a read enable signal (re), and an output data line (16 bits). When the write enable signal is low, the input data should be stored in the DRAM cell; when the read enable signal is low, the stored data should be output on the data line.
module dram_cell (  
    input wire [15:0] data_in,  
    input wire we,  
    input wire re,  
    output reg [15:0] data_out  
);  
    reg [15:0] memory;  

    always @(posedge we) begin  
        memory <= data_in;  
    end  

    always @(posedge re) begin  
        data_out <= memory;  
    end  
endmodule
